mapper.select:
/* com.erns.coching.mail.mapper.MailDAO.selectWillSend */
SELECT
FROM T_BATCH_MAIL AA
AND AA.RESULT in ('R', 'F') AND AA.ERR_CNT < 2
ORDER BY AA.BATCH_SEQ ASC LIMIT #{value ,jdbcType=INTEGER}

mapper.update:
/* com.erns.coching.mail.mapper.MailDAO.updateSuccess */

UPDATE T_BATCH_MAIL SET
	RESULT = 'S'
						   , SENT_DATE = NOW()
						   , CHNG_DTTM = NOW()

WHERE BATCH_SEQ = #{batchSeq	,jdbcType=INTEGER}

/* com.erns.coching.mail.mapper.MailDAO.updateFail */
UPDATE T_BATCH_MAIL SET RESULT = 'F' , RESULT_DATA = CAST(#{resultData} AS jsonb) , ERR_CNT = ERR_CNT + 1 , CHNG_DTTM = NOW()
WHERE BATCH_SEQ = #{batchSeq ,jdbcType=INTEGER}

mapper.insert:
/* com.erns.coching.mail.mapper.MailDAO.insert */

	SELECT nextval('seq_t_batch_mail')


INSERT INTO T_BATCH_MAIL (
BATCH_SEQ
, RESULT
, RESULT_DATA
, ERR_CNT
, SEND_DATE
, SENT_DATE
, MEMB_SEQ
, TO_EMAIL
, PRIORITY
, TITLE
, CONTENT
, MAIL_SEQ
, FILE_ID
)
VALUES (
#{batchSeq	,jdbcType=INTEGER}
, 'R'
, NULL
, 0
, COALESCE(#{sendDate	,jdbcType=VARCHAR}
, TO_CHAR(now(), 'YYYY-MM-DD HH24:mi:SS'))
, NULL
, #{membSeq     ,jdbcType=INTEGER}
, #{toEmail		,jdbcType=VARCHAR}
, #{priority	,jdbcType=VARCHAR}
, #{title		,jdbcType=VARCHAR}
, #{content		,jdbcType=VARCHAR}
, #{mailSeq		,jdbcType=INTEGER}
, #{fileId		,jdbcType=VARCHAR}
)
